    #[test]
    fn test_daterange_tag_contains_id_and_start() {
        let dr = HlsDateRange {
            id: "splice-1".to_string(),
            class: None,
            start_date_ms: 1_700_000_000_000i64,
            end_date_ms: None,
            duration_secs: Some(30.0),
            planned_duration_secs: None,
            end_on_next: false,
            client_attributes: Vec::new(),
            scte35_cmd: None,
        };
        let line = dr.to_tag_line();
        assert!(
            line.contains("#EXT-X-DATERANGE:ID=\"splice-1\""),
            "line={line}"
        );
        assert!(line.contains("START-DATE="), "line={line}");
        assert!(line.contains("DURATION=30.000"), "line={line}");
    }

