    // ── EXT-X-SKIP tests ──────────────────────────────────────────────────────

    #[test]
    fn test_ext_x_skip_tag_line() {
        let skip = HlsSkip {
            skipped_segments: 5,
            recently_removed_dateranges: Vec::new(),
        };
        let line = skip.to_tag_line();
        assert_eq!(line, "#EXT-X-SKIP:SKIPPED-SEGMENTS=5");
    }

    #[test]
    fn test_ext_x_skip_with_removed_dateranges() {
        let skip = HlsSkip {
            skipped_segments: 3,
            recently_removed_dateranges: vec!["range-1".to_string(), "range-2".to_string()],
        };
        let line = skip.to_tag_line();
        assert!(line.contains("RECENTLY-REMOVED-DATERANGES="), "line={line}");
        assert!(line.contains("range-1"), "line={line}");
    }

    #[test]
    fn test_media_playlist_with_skip_uses_version_9() {
        let manifest = HlsManifest {
            target_duration: 6,
            media_sequence: 5,
            segments: (5..8).map(|i| make_segment(6.0, i)).collect(),
            is_endlist: false,
            allow_cache: false,
            skip: Some(HlsSkip {
                skipped_segments: 5,
                recently_removed_dateranges: Vec::new(),
            }),
        };
        let output = build_media_playlist(&manifest);
        assert!(
            output.contains("#EXT-X-VERSION:9"),
            "delta playlist should be version 9; output={output}"
        );
        assert!(
            output.contains("#EXT-X-SKIP:SKIPPED-SEGMENTS=5"),
            "output={output}"
        );
    }

    #[test]
    fn test_media_playlist_without_skip_uses_version_3() {
        let manifest = make_manifest_builder();
        let output = build_media_playlist(&manifest);
        assert!(
            output.contains("#EXT-X-VERSION:3"),
            "non-delta playlist should be version 3; output={output}"
        );
    }
